BaseField.Formula:
if ([Percent_Cards] == -7 && [Percent_BlackJack] == -7 && [Percent_Bingo] == -7 && [Percent_Dice] == -7 && [Percent_Dog Racing] == -7 && [Percent_Horse Racing] == -7 && [Percent_Keno] == -7 && [Percent_Lottery] == -7 && [Percent_Game of Skill] == -7 && [Percent_Poker] == -7 && [Percent_Raffles] == -7 && [Percent_Roulette] == -7 && [Percent_Slot Machines] == -7 && [Percent_Sporting Events] == -7 && [Percent_Stock Financial] == -7 && [Percent_Video Poker] == -7 && [Percent_Other] == -7 && [Percent_Internet Gambling] == -7
 ) {
    -7
}
else {
    [Percent_Cards] + [Percent_BlackJack] + [Percent_Bingo] + [Percent_Dice] + [Percent_Dog Racing] + [Percent_Horse Racing] + [Percent_Keno] + [Percent_Lottery] + [Percent_Game of Skill] + [Percent_Poker] + [Percent_Raffles] + [Percent_Roulette] + [Percent_Slot Machines] + [Percent_Sporting Events] + [Percent_Stock Financial] + [Percent_Video Poker] + [Percent_Other] + [Percent_Internet Gambling]
}

