}

//Call to display form side validation error message.  This will not display a message if the nodejs logic needs to run.
VV.Form.Template.DisplayMessaging();

//Pass in ControlName as the string that represents the name of the control.
//Setup Variable for error reporting.
var ErrorReporting = true;

//RunAll is to validate all fields before submitting.
var RunAll = false;
if (ControlName == null) {
    RunAll = true;
}

//Used to setup a variable that is accessible to any functions at the template level.
if (typeof (VV.Form.Template.SectStatusTreatmentHistory) == 'undefined') {
    VV.Form.Template.SetupTemplateVariables();
}

//Following section is the central logic to validate each field.  If a ControlName is passed, then we only validate that control.
//If no control name is passed, then all items are validated.

/*
Removed entirety of previous validation script. Each field is now being validated on blur individually, and data entry is required in all fields. 
*/

//Validate each field on blur individually as long as Gmblinfo_None is not yes (available to AIs only)
//Disallow the user from selecting skipped. Otherwise allow the user to leave the drop-down as Select Item.

if (VV.Form.getDropDownListText('GmblInfo_None') != 'Yes') {
    //Venue_Bingo Hall
    if (ControlName == 'Venue_Bingo Hall' || RunAll) {
        /* //Removing this portion of each field validation
        if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Venue_Bingo Hall'), 'DDSelect') == false) {
            VV.Form.SetValidationErrorMessageOnField('Venue_Bingo Hall', 'A value needs to be selected.');
            ErrorReporting = false;
        }
        else */
        if (VV.Form.getDropDownListText('Venue_Bingo Hall') == 'Skipped Due to a Previous Response') {
            VV.Form.SetValidationErrorMessageOnField('Venue_Bingo Hall', 'This is not a valid selection.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('Venue_Bingo Hall');
        }
    }
