//Get the type of client
var typeOfClient = VV.Form.getDropDownListText('Type of Client');
var chkGambled = VV.Form.getDropDownListText('GmblInfo_None');

//Following section is the central logic to validate each field.  If a ControlName is passed, then we only validate that control.
//If no control name is passed, then all items are validated.

// Validation of Percentage of total gambling time on various activities.
// Shown on intake only. GmblInfo_None is presented to AI's only, so if that's yes then no need to validate this section.

if (RunAll) {
    if (typeOfClient == 'Patient') {
        if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Percentage Total'), '100', 'GreaterThan') == true) {
            VV.Form.SetValidationErrorMessageOnField('txtGamblingPercentage', 'This field cannot be greater than 100.');
            ErrorReporting = false;
        }
        else if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Percentage Total'), '100', 'LessThan') == true) {
            VV.Form.SetValidationErrorMessageOnField('txtGamblingPercentage', 'This field cannot be less than 100.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('txtGamblingPercentage');
        }
    }
    else if (chkGambled == 'No' && typeOfClient == 'Affected Individual') {
        if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Percentage Total'), '100', 'GreaterThan') == true) {
            VV.Form.SetValidationErrorMessageOnField('txtGamblingPercentage', 'This field cannot be greater than 100.');
            ErrorReporting = false;
        }
        else if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Percentage Total'), '100', 'LessThan') == true) {
            VV.Form.SetValidationErrorMessageOnField('txtGamblingPercentage', 'This field cannot be less than 100 when affected individual has registered types of gambling.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('txtGamblingPercentage');
        }
    }
    else {
        VV.Form.ClearValidationErrorOnField('txtGamblingPercentage');
    }
}

