// If checking each input on blur, check that they're not all no at the end
// Also validate that at least one item is marked as "yes"
var fieldArray = ['CoOccuring_Diag_Diabetes', 'CoOccuring_Diag_None', 'CoOccuring_Diag_Liver', 'CoOccuring_Diag_Cancer', 'CoOccuring_Diag_Respiratory', 'CoOccuring_Diag_HeartDisease', 'CoOccuring_Diag_Obesity', 'CoOccuring_Diag_Stroke', 'CoOccuring_Diag_HIV', 'CoOccuring_Diag_Hypertension', 'CoOccuring_Diag_Ulcer', 'Health_Other_Checkbox'];
var measuredFields = VV.Form.Global.measureArrayofValues(fieldArray, 'DDText');
var numberofFields = fieldArray.length;
var flagsSet = false;
var yesResponseFound = false;

measuredFields.forEach(function (response) {
    if (response.Value == 'No' && response.Count == numberofFields) {
        VV.Form.Global.flagErrorClearError(fieldArray, 'error', 'At least one value must be selected');
        flagsSet = true;
        ErrorReporting = false;
    }
    else if (response.Value == 'Yes') {
        yesResponseFound = true;
    }
});

if (RunAll && yesResponseFound == false) {
    VV.Form.Global.flagErrorClearError(fieldArray, 'error', 'At least one value must be selected');
    flagsSet = true;
    ErrorReporting = false;
}

if (flagsSet == false) {
    fieldArray.forEach(function (fieldName) {
        VV.Form.ClearValidationErrorOnField(fieldName);
    });
}


//Set error values here.  This will be fired before previous section because previous section waiting for RESTAPI.
VV.Form.Template.SectStatus12Mo[1] = 1;
if (ErrorReporting == false) {
    VV.Form.Template.SectStatus12Mo[2] = 1;
} else {
    VV.Form.Template.SectStatus12Mo[2] = 0;
}

var messageData = '';
var callCloseClientIntake = function () {
    var apiVer = "v1";
    var formData = VV.Form.getFormDataCollection();
    var data = JSON.stringify(formData);
    var requestObject = $.ajax({
        type: "POST",
        url: VV.BaseAppUrl + 'api/' + apiVer + '/' + VV.CustomerAlias + '/' + VV.CustomerDatabaseAlias + '/scripts?name=FollowupOutpatientClose',
        contentType: "application/json; charset=utf-8",
        data: data,
        success: '',
        error: ''
    });

    return requestObject;
};

$.when(
         callCloseClientIntake()
      ).always(function (arg1) {
          if (typeof (arg1.status) != 'undefined') {
              messageData = "A status code of " + arg1.status + " returned from the server.  There is a communication problem with the CalGETS web servers.  If this continues, please contact Office of Problem Gaming and communicate to them this message and where it occured.";
          }
          else if (typeof (arg1.statusCode) != 'undefined') {
              messageData = "A status code of " + arg1.statusCode + " with a message of '" + arg1.errorMessages[0].message + "' returned from the server.  This may mean that the servers to run the business logic are not available.";
          }
          else if (typeof (arg1.meta.status) != 'undefined') {
              if (arg1.meta.status == '200') {
                  if (typeof (arg1.data[0]) != 'undefined') {
                      var messageReturned = arg1.data[0];
                      if (messageReturned.substr(0, 41) == 'This form has been submitted successfully') {
                          messageData = arg1.data[0] + '\n';
                          VV.Form.Template.SetupTemplateVariables();
                          VV.Form.DoPostbackSave();
                          VV.Form.HideLoadingPanel();

                      }
                      else {
                          messageData = arg1.data[0] + '\n';
                      }
                  }
                  else {
                      messageData = arg1.data.error + '\n';
                      //VV.Form.Global.DisplayMessaging(messageData);
                  }
              }
          }
          else {
              messageData = 'Communication codes from the server were unhandled.';
          }
          alert(messageData);
      });

//ValidationGamblerAnon function for Treatment Questionnaire

//Setup Variable for error reporting.
var ErrorReporting = true;

//RunAll is to validate all fields before submitting.
var RunAll = false;
if (ControlName == null) {
    RunAll = true;
}

//Used to setup a variable that is accessible to any functions at the template level.
if (typeof (VV.Form.Template.SectStatusTreatmentHistory) == 'undefined') {
    VV.Form.Template.SetupTemplateVariables();
}

//Following section is the central logic to validate each field.  If a ControlName is passed, then we only validate that control.
//If no control name is passed, then all items are validated.

//This script is run without any conditions from ValidateAll()

if (ControlName == 'Treatment_GA Meetings' || RunAll) {
    if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Treatment_GA Meetings'), '0', 'GreaterThanEqualTo') == false) {
        VV.Form.SetValidationErrorMessageOnField('Treatment_GA Meetings', 'Value needs to be greater than or equal to zero.');
        ErrorReporting = false;
    }
    else {
        VV.Form.ClearValidationErrorOnField('Treatment_GA Meetings');
    }

    var yesFieldsSkipped = ['Treatment_GA Not Attending'];
    var zeroFieldsSkipped = ['Treatment_GA Sponsor', 'Treatment_GA Commitment'];

    if (VV.Form.GetFieldValue('Treatment_GA Meetings') == '0') {
        VV.Form.Global.SetToSkipped(zeroFieldsSkipped);
    }

    if (Number(VV.Form.GetFieldValue('Treatment_GA Meetings')) > 0) {
        VV.Form.Global.SetToSkipped(yesFieldsSkipped);
    }
}

//Set to blank only on blur from item, otherwise users will lose inputs upon runall
//Also trigger a change from Treatment_GA Not Attending so the computer thinks a real person selected the option, which allows it to be retained on save.
    //Otherwise it reverts to select item bc the programmatic change doesn't stick
if (ControlName == 'Treatment_GA Meetings') {
    var yesFieldsSkipped = ['Treatment_GA Not Attending'];
    var zeroFieldsSkipped = ['Treatment_GA Sponsor', 'Treatment_GA Commitment'];

    if (VV.Form.GetFieldValue('Treatment_GA Meetings') == '0') {
        VV.Form.Global.SetToBlank('DropDown', yesFieldsSkipped);
    }

    if (Number(VV.Form.GetFieldValue('Treatment_GA Meetings')) > 0) {
        VV.Form.Global.SetToBlank('DropDown', zeroFieldsSkipped);
    }

    setTimeout(function () {
        var ddl = $('[VVFieldName="Treatment_GA Not Attending"]');
        ddl.trigger("change");
    }, 500);
}

if (ControlName == 'Treatment_GA Sponsor' || RunAll) {
    if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Treatment_GA Meetings'), '0', 'GreaterThan') == true) {
        if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Treatment_GA Sponsor'), 'DDSelect') == false) {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Sponsor', 'Yes or No needs to be selected since the number of meetings is greater than zero.');
            ErrorReporting = false;
        }
        else if (VV.Form.getDropDownListText('Treatment_GA Sponsor') == 'Skipped Due to a Previous Response') {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Sponsor', 'This is not a valid selection.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('Treatment_GA Sponsor');
        }
    }
    else {
        VV.Form.ClearValidationErrorOnField('Treatment_GA Sponsor');
    }
}

if (ControlName == 'Treatment_GA Commitment' || RunAll) {
    if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Treatment_GA Meetings'), '0', 'GreaterThan') == true) {
        if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Treatment_GA Commitment'), 'DDSelect') == false) {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Commitment', 'Yes or No needs to be selected since the number of meetings is greater than zero.');
            ErrorReporting = false;
        }
        else if (VV.Form.getDropDownListText('Treatment_GA Commitment') == 'Skipped Due to a Previous Response') {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Commitment', 'This is not a valid selection.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('Treatment_GA Commitment');
        }
    }
    else {
        VV.Form.ClearValidationErrorOnField('Treatment_GA Commitment');
    }
}

if (ControlName == 'Treatment_GA Not Attending' || RunAll) {
    if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Treatment_GA Meetings'), '0', 'Equals') == true) {
        if (VV.Form.Global.CentralValidation(VV.Form.getDropDownListText('Treatment_GA Not Attending'), 'DDSelect') == false) {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Not Attending', 'A value needs to be selected.');
            ErrorReporting = false;
        }
        else if (VV.Form.getDropDownListText('Treatment_GA Not Attending') == 'Skipped Due to a Previous Response') {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Not Attending', 'This is not a valid selection.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('Treatment_GA Not Attending');
        }
    } else {
        VV.Form.ClearValidationErrorOnField('Treatment_GA Not Attending');
    }
}

if (ControlName == 'Treatment_GA Other' || RunAll) {
    if (VV.Form.getDropDownListText('Treatment_GA Not Attending') == 'Other') {
        if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue('Treatment_GA Other'), 'Blank') == false) {
            VV.Form.SetValidationErrorMessageOnField('Treatment_GA Other', 'A value needs to be entered.');
            ErrorReporting = false;
        }
        else {
            VV.Form.ClearValidationErrorOnField('Treatment_GA Other');
        }
    } else {
        VV.Form.ClearValidationErrorOnField('Treatment_GA Other');
    }
}

