var messageData = '';
var callVerifyQuestionnaire = function () {
    var apiVer = "v1";
    var formData = VV.Form.getFormDataCollection();
    var questionnaireTypeText = { id: '', name: 'Questionnaire Type Text', value: VV.Form.getDropDownListText('Questionnaire Type') };
    formData.push(questionnaireTypeText);
    var data = JSON.stringify(formData);
    var requestObject = $.ajax({
        type: "POST",
        url: VV.BaseAppUrl + 'api/' + apiVer + '/' + VV.CustomerAlias + '/' + VV.CustomerDatabaseAlias + '/scripts?name=TreatmentQuestionnaireSubmit',
        contentType: "application/json; charset=utf-8",
        data: data,
        success: '',
        error: ''
    });

    return requestObject;
};

$.when(
    callVerifyQuestionnaire()
).always(function (arg1) {
    if (typeof (arg1.status) != 'undefined') {
        messageData = "A status code of " + arg1.status + " returned from the server.  There is a communication problem with the CalGETS web servers.  If this continues, please contact Office of Problem Gaming and communicate to them this message and where it occured.";
        VV.Form.Template.DisplayMessaging(messageData);
    }
    else if (typeof (arg1.statusCode) != 'undefined') {
        messageData = "A status code of " + arg1.statusCode + " with a message of '" + arg1.errorMessages[0].message + "' returned from the server.  This may mean that the servers to run the business logic are not available.";
        VV.Form.Template.DisplayMessaging(messageData);
    }
    else if (typeof (arg1.meta.status) != 'undefined') {
        if (arg1.meta.status == '200') {
            if (typeof (arg1.data[0]) != 'undefined') {
                var messageReturned = arg1.data[0];
                if (messageReturned.substr(0, 41) == 'This form has been submitted successfully') {
                    VV.Form.Template.QuestNodejs[1] = 1;
                    VV.Form.Template.QuestNodejs[2] = 0;
                    messageData = arg1.data[0] + '\n';
                    VV.Form.Template.DisplayMessaging(messageData);
                    VV.Form.DoPostbackSave();
                }
                else {
                    VV.Form.Template.QuestNodejs[1] = 1;
                    VV.Form.Template.QuestNodejs[2] = 1;
                    messageData = arg1.data[0] + '\n';
                    VV.Form.Template.DisplayMessaging(messageData);
                }
            }
            else {
                messageData = arg1.data.error + '\n';
                VV.Form.Global.DisplayMessaging(messageData);
            }
        }
    }
    else {
        messageData = 'Communication codes from the server were unhandled.';
        VV.Form.Template.QuestNodejs[2] = 1;
        VV.Form.Template.DisplayMessaging(messageData);
    }
    //VV.Form.Template.DisplayMessaging(messageData);
    //Added Display Messaging to each statement above and commented out the final DisplayMessaging. 01/28/2019 - Nikola Mathews
});

