        VV.Form.Template.SectStatusProvider[2] == 0 &&
        VV.Form.Template.SectStatusSliders[2] == 0 &&
        VV.Form.Template.SectStatusInterpersonal[2] == 0 &&
        VV.Form.Template.SectStatusPreferredGambling[2] == 0
    ) {
        VV.Form.Template.SetupTemplateVariables();
        VV.Form.DoPostbackSave();
        VV.Form.HideLoadingPanel();
        alert(MessageInfo);
    }
    //There is an error somewhere that was encountered.
    else if (
        VV.Form.Template.SectStatusTreatmentHistory[2] == 1 ||
        VV.Form.Template.SectStatusPercentages[2] == 1 ||
        VV.Form.Template.SectStatusIllegalActs[2] == 1 ||
        VV.Form.Template.SectStatusVenues[2] == 1 ||
        VV.Form.Template.SectStatus12Mo[2] == 1 ||
        VV.Form.Template.SectStatusCoOccuring[2] == 1 ||
        VV.Form.Template.SectStatusCoOccuring1[2] == 1 ||
        VV.Form.Template.SectStatusCoOccuring2[2] == 1 ||
        VV.Form.Template.SectStatusFollowup[2] == 1 ||
        VV.Form.Template.SectStatusCPGTSP[2] == 1 ||
        VV.Form.Template.SectStatusProbGambler[2] == 1 ||
        VV.Form.Template.SectStatusHeader[2] == 1 ||
        VV.Form.Template.SectStatusGamblerInfo[2] == 1 ||
        VV.Form.Template.SectStatusFrequency[2] == 1 ||
        VV.Form.Template.SectStatusGamAnon[2] == 1 ||
        VV.Form.Template.QuestNodejs[2] == 1 ||
        VV.Form.Template.SectStatusWeight[2] == 1 ||
        VV.Form.Template.SectStatusGoal[2] == 1 ||
        VV.Form.Template.SectStatusChallenge[2] == 1 ||
        VV.Form.Template.SectStatusInterpersonal[2] == 1 ||
        VV.Form.Template.SectStatusPreferredGambling[2] == 1 ||
        (VV.Form.Template.SectStatusProvider[2] == 1 && VV.Form.Template.SectStatusSliders[2] == 1)
    ) {
        VV.Form.Template.SetupTemplateVariables();
        VV.Form.HideLoadingPanel();
        alert(MessageInfo);
    } else {
        return; //maxwell added return; line, delete if trouble
    }
}

