var requestMigrateData = function() {
  var rawData = {
    placeHolder: "placeHolder"
  };

  var data = JSON.stringify(rawData);
  var request = $.ajax({
    type: "POST",
    url: VV.BaseAppUrl + "api/v1/" + VV.CustomerAlias + "/" + VV.CustomerDatabaseAlias + "/scripts?name=migrateData",
    contentType: 'application/json; charset=utf-8',
    data: data,
    success: '',
    error: ''
  });

  return request;

}; 

return requestMigrateData().then(function(messageData) {
  /*For Testing*/
  console.log(messageData);
  //return messageData.data.message;
});

