}

// If checking each input on blur, check that they're not all no at the end
// Also validate that at least one item is marked as "yes"
var fieldArray = [
    "PreferredHarmful_Most_Slots",
    "PreferredHarmful_Most_Blackjack",
    "PreferredHarmful_Most_Poker",
    "PreferredHarmful_Most_Sports",
    "PreferredHarmful_Most_Lottery",
    "PreferredHarmful_Most_Video",
    "PreferredHarmful_Most_Horse",
    "PreferredHarmful_Most_Stocks",
    "PreferredHarmful_Most_Other",
];
var measuredFields = VV.Form.Global.measureArrayofValues(fieldArray, "DDText");
var numberofFields = fieldArray.length;
var flagsSet = false;
var yesResponseFound = false;

measuredFields.forEach(function (response) {
    if (response.Value == "No" && response.Count == numberofFields) {
        VV.Form.Global.flagErrorClearError(fieldArray, "error", "At least one form of gambling needs to be selected.");
        flagsSet = true;
        ErrorReporting = false;
    } else if (response.Value == "Yes") {
        yesResponseFound = true;
    }
});

if (RunAll && yesResponseFound == false) {
    VV.Form.Global.flagErrorClearError(fieldArray, "error", "At least one form of gambling needs to be selected");
    flagsSet = true;
    ErrorReporting = false;
}

if (flagsSet == false) {
    fieldArray.forEach(function (fieldName) {
        if (VV.Form.getDropDownListText(fieldName) != "Skipped Due to a Previous Response") {
            VV.Form.ClearValidationErrorOnField(fieldName);
        } else {
            ErrorReporting = false;
        }
    });
}

